import{_ as r,o as a,c as e,ae as o}from"./chunks/framework.Dzr56EFm.js";const d=JSON.parse('{"title":"大厂战略 - 2026-05-03","description":"","frontmatter":{"date":"2026-05-03T00:00:00.000Z","category":"BigTech"},"headers":[],"relativePath":"daily/2026-05-03-bigtech.md","filePath":"daily/2026-05-03-bigtech.md"}'),n={name:"daily/2026-05-03-bigtech.md"};function s(p,t,i,g,l,h){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="大厂战略-2026-05-03" tabindex="-1">大厂战略 - 2026-05-03 <a class="header-anchor" href="#大厂战略-2026-05-03" aria-label="Permalink to &quot;大厂战略 - 2026-05-03&quot;">​</a></h1><blockquote><p>OpenAI、Google、Apple、Microsoft、Meta、Amazon战略</p></blockquote><h2 id="今日概览" tabindex="-1">今日概览 <a class="header-anchor" href="#今日概览" aria-label="Permalink to &quot;今日概览&quot;">​</a></h2><p>今日大厂战略领域主要动态包括微软强调AI战略规划的四个核心领域，微软AI在商业战略中的应用，EY将AI融入全球战略，以及Meta与博通和NVIDIA的合作。最值得关注的是Meta与博通合作开发定制AI芯片，以及Meta与NVIDIA建立的长期基础设施合作伙伴关系，这两项合作将推动AI技术的全球普及和基础设施发展。</p><hr><h3 id="_1-制定你的ai战略-云采用框架-微软学习" tabindex="-1">1. 制定你的AI战略 - 云采用框架 | 微软学习 <a class="header-anchor" href="#_1-制定你的ai战略-云采用框架-微软学习" aria-label="Permalink to &quot;1. 制定你的AI战略 - 云采用框架 | 微软学习&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://learn.microsoft.com/en-us/azure/cloud-adoption-framework/ai/strategy" target="_blank" rel="noreferrer">Create your AI strategy - Cloud Adoption Framework | Microsoft Learn</a></p><p><strong>一句话摘要</strong>: 规划AI战略需关注四个核心领域：业务价值、技术选择、数据治理和负责任的AI实践。</p><p><strong>能解决什么问题</strong>: 帮助组织制定结构化的AI战略，以实现业务价值和合规性。</p><p><strong>产品应用</strong>: 适用于各规模组织，通过微软AI技术实现业务数据预测和产品管理。</p><p><strong>示例场景</strong>: 虚构公司Contoso使用AI战略管理电商平台和销售代表工具。</p><hr><h3 id="_2-商业和企业战略中的人工智能-微软ai" tabindex="-1">2. 商业和企业战略中的人工智能 | 微软AI <a class="header-anchor" href="#_2-商业和企业战略中的人工智能-微软ai" aria-label="Permalink to &quot;2. 商业和企业战略中的人工智能 | 微软AI&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/ai/ai-business-value-and-benefits" target="_blank" rel="noreferrer">AI in Business and Corporate Strategy | Microsoft AI</a></p><p><strong>一句话摘要</strong>: 微软AI通过高级工具显著提升销售策略和成果。</p><p><strong>能解决什么问题</strong>: 解决业务操作效率低和市场机会识别不足的问题。</p><p><strong>产品应用</strong>: 可以应用到实际产品中，通过自动化和数据分析提升业务效率。</p><p><strong>示例场景</strong>: 使用AI自动化处理电子邮件起草和数据录入。</p><hr><h3 id="_3-ai作为平台转变而非另一项实验" tabindex="-1">3. AI作为平台转变而非另一项实验 <a class="header-anchor" href="#_3-ai作为平台转变而非另一项实验" aria-label="Permalink to &quot;3. AI作为平台转变而非另一项实验&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.microsoft.com/en-us/industry/microsoft-in-business/thought-leadership/2026/04/21/ai-as-a-platform-shift-not-another-experiment/" target="_blank" rel="noreferrer">AI as a platform shift, not another experiment - Microsoft in Business Blogs</a></p><p><strong>一句话摘要</strong>: EY将AI融入全球战略，重塑税务、审计、咨询和顾问服务。</p><p><strong>能解决什么问题</strong>: 如何将AI战略转化为大规模实际执行，提升企业效率和信任。</p><p><strong>产品应用</strong>: 应用于税务、审计等领域，通过AI加速数据处理和洞察发现。</p><p><strong>示例场景</strong>: EY利用AI加速文档审查，提升审计质量。</p><hr><h3 id="_4-meta与博通合作开发定制ai芯片" tabindex="-1">4. Meta与博通合作开发定制AI芯片 <a class="header-anchor" href="#_4-meta与博通合作开发定制ai芯片" aria-label="Permalink to &quot;4. Meta与博通合作开发定制AI芯片&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://about.fb.com/news/2026/04/meta-partners-with-broadcom-to-co-develop-custom-ai-silicon/" target="_blank" rel="noreferrer">Meta Partners With Broadcom to Co-Develop Custom AI Silicon</a></p><p><strong>一句话摘要</strong>: Meta与博通合作开发定制AI芯片，推动个人超级智能全球普及。</p><p><strong>能解决什么问题</strong>: 解决大规模AI硬件需求，提升性能和效率。</p><p><strong>产品应用</strong>: 应用于全球范围内的AI基础设施，提供定制计算基础。</p><p><strong>示例场景</strong>: 为数十亿人提供个人超级智能服务。</p><hr><h3 id="_5-meta与nvidia宣布长期基础设施合作伙伴关系" tabindex="-1">5. Meta与NVIDIA宣布长期基础设施合作伙伴关系 <a class="header-anchor" href="#_5-meta与nvidia宣布长期基础设施合作伙伴关系" aria-label="Permalink to &quot;5. Meta与NVIDIA宣布长期基础设施合作伙伴关系&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://about.fb.com/news/2026/02/meta-nvidia-announce-long-term-infrastructure-partnership/" target="_blank" rel="noreferrer">Meta and NVIDIA Announce Long-Term Infrastructure Partnership</a></p><p><strong>一句话摘要</strong>: Meta与NVIDIA建立多年战略合作，推进AI基础设施发展。</p><p><strong>能解决什么问题</strong>: 解决大规模AI训练和推理中性能与效率问题。</p><p><strong>产品应用</strong>: 应用于数据中心，优化AI训练和推理，提升能效。</p><p><strong>示例场景</strong>: 为数十亿用户提供个性化推荐系统。</p><hr><h3 id="_6-ai时代下的领导力——微软采纳" tabindex="-1">6. AI时代下的领导力——微软采纳 <a class="header-anchor" href="#_6-ai时代下的领导力——微软采纳" aria-label="Permalink to &quot;6. AI时代下的领导力——微软采纳&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://adoption.microsoft.com/en-us/leading-in-the-era-of-ai/" target="_blank" rel="noreferrer">Leading in the era of AI – Microsoft Adoption</a></p><p><strong>一句话摘要</strong>: 为各类领导者提供AI能力采纳的实用指导。</p><p><strong>能解决什么问题</strong>: 帮助企业领导者理解并最大化AI在业务中的应用。</p><p><strong>产品应用</strong>: 可以应用到产品中，通过AI工具提升工作效率和业务价值。</p><p><strong>示例场景</strong>: 企业通过微软365 Copilot提升团队协作效率。</p><hr><h3 id="_7-扩展meta定制硅芯片以增强ai工作负载" tabindex="-1">7. 扩展Meta定制硅芯片以增强AI工作负载 <a class="header-anchor" href="#_7-扩展meta定制硅芯片以增强ai工作负载" aria-label="Permalink to &quot;7. 扩展Meta定制硅芯片以增强AI工作负载&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://about.fb.com/news/2026/03/expanding-metas-custom-silicon-to-power-our-ai-workloads/" target="_blank" rel="noreferrer">Expanding Meta&#39;s Custom Silicon to Power Our AI Workloads</a></p><p><strong>一句话摘要</strong>: Meta两年内开发四代新芯片，提升计算、内存带宽和效率。</p><p><strong>能解决什么问题</strong>: 解决AI工作负载增长和演进中的计算和效率问题。</p><p><strong>产品应用</strong>: 可应用于排名、推荐训练和GenAI推理生产等AI基础设施。</p><p><strong>示例场景</strong>: 用于Facebook推荐系统的训练和推理加速。</p><hr><h3 id="_8-苹果未来四年将在美投资超5000亿美元" tabindex="-1">8. 苹果未来四年将在美投资超5000亿美元 <a class="header-anchor" href="#_8-苹果未来四年将在美投资超5000亿美元" aria-label="Permalink to &quot;8. 苹果未来四年将在美投资超5000亿美元&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://www.apple.com/newsroom/2025/02/apple-will-spend-more-than-500-billion-usd-in-the-us-over-the-next-four-years/" target="_blank" rel="noreferrer">Apple will spend more than $500 billion in the U.S. over the next four ...</a></p><p><strong>一句话摘要</strong>: 苹果宣布将投资5000亿美元支持美国创新和先进制造</p><p><strong>能解决什么问题</strong>: 促进美国高技能制造业发展，提升人工智能和硅工程能力</p><p><strong>产品应用</strong>: 可应用于研发中心和制造工厂，推动技术创新和人才培养</p><p><strong>示例场景</strong>: 在底特律开设制造学院，支持中小企业转型</p><hr><h3 id="_9-苹果新任ceo如何改变ai战略" tabindex="-1">9. 苹果新任CEO如何改变AI战略 <a class="header-anchor" href="#_9-苹果新任ceo如何改变ai战略" aria-label="Permalink to &quot;9. 苹果新任CEO如何改变AI战略&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://podcasts.apple.com/in/podcast/how-apples-ai-strategy-changes-with-a-new-ceo/id1680633614?i=1000762944585" target="_blank" rel="noreferrer">How Apple&#39;s AI Strategy Change…–The AI Daily Brief: Artificial Intelligence News and Analysis – Apple Podcasts</a></p><p><strong>一句话摘要</strong>: 苹果新CEO约翰·特纳斯面临制定公司未来AI战略的挑战。</p><p><strong>能解决什么问题</strong>: 如何利用AI技术提升产品竞争力和市场优势。</p><p><strong>产品应用</strong>: 可以应用于智能设备和软件服务，提高用户体验和效率。</p><p><strong>示例场景</strong>: Siri语音助手通过AI技术提供个性化服务。</p><hr><h3 id="_10-meta与amd达成长期人工智能基础设施合作协议" tabindex="-1">10. Meta与AMD达成长期人工智能基础设施合作协议 <a class="header-anchor" href="#_10-meta与amd达成长期人工智能基础设施合作协议" aria-label="Permalink to &quot;10. Meta与AMD达成长期人工智能基础设施合作协议&quot;">​</a></h3><p><strong>原文标题</strong>: <a href="https://about.fb.com/news/2026/02/meta-amd-partner-longterm-ai-infrastructure-agreement/" target="_blank" rel="noreferrer">Meta and AMD Partner for Longterm AI Infrastructure Agreement</a></p><p><strong>一句话摘要</strong>: Meta与AMD合作，共同推动AI发展</p><p><strong>能解决什么问题</strong>: 解决AI工作负载增长带来的计算需求</p><p><strong>产品应用</strong>: 应用于Meta的AI基础设施，提升计算能力</p><p><strong>示例场景</strong>: Meta利用AMD技术构建个人超级智能</p><hr>',75)])])}const A=r(n,[["render",s]]);export{d as __pageData,A as default};
